import React from 'react';

// Sidebar navigation for admin dashboard
// Allows navigation between user, order, and product management
export default function AdminSidebar({ current, onNavigate }) {
  return (
    <aside className="h-screen w-60 bg-white shadow-lg flex flex-col py-8 px-4 border-r border-gray-100">
      <h2 className="text-2xl font-bold text-green-600 mb-10 text-center">Admin</h2>
      <nav className="flex flex-col gap-4">
        <button
          className={`text-left px-4 py-2 rounded font-medium transition ${current === 'dashboard' ? 'bg-green-100 text-green-700' : 'hover:bg-gray-100 text-gray-700'}`}
          onClick={() => onNavigate('dashboard')}
        >Dashboard</button>
        <button
          className={`text-left px-4 py-2 rounded font-medium transition ${current === 'user' ? 'bg-green-100 text-green-700' : 'hover:bg-gray-100 text-gray-700'}`}
          onClick={() => onNavigate('user')}
        >User Management</button>
        <button
          className={`text-left px-4 py-2 rounded font-medium transition ${current === 'order' ? 'bg-green-100 text-green-700' : 'hover:bg-gray-100 text-gray-700'}`}
          onClick={() => onNavigate('order')}
        >Order Management</button>
        <button
          className={`text-left px-4 py-2 rounded font-medium transition ${current === 'product' ? 'bg-green-100 text-green-700' : 'hover:bg-gray-100 text-gray-700'}`}
          onClick={() => onNavigate('product')}
        >Product Management</button>
      </nav>
    </aside>
  );
}
